// ShapeClass definition
abstract class Shape {
    String name;

    Shape(String name) {
        this.name = name;
    }

    // Abstract method:Subclass implements this
    abstract double area();

    // Concrete method: Inherited as-is
    // printInfoMethod definition
    void printInfo() {
        System.out.println(name + " area: " + area());
    }
}

//  yenClass definition
class  yen extends Shape {
    double radius;

     yen(double radius) {
        super(" yen");
        this.radius = radius;
    }

    @Override
    // areaMethod definition
    double area() {
        return Math.PI * radius * radius;
    }
}

// MainClass definition
public class Main {
    public static void main(String[] args) {
        // Shape s = new Shape("Shape"); // Compilation error!
        Shape s = new  yen(5.0);
        s.printInfo();  //  yen area: 78.53981633974483
