// PrintableInterface definition
interface Printable {
    void print();  // public abstract is implicitly added
}

// ResizableInterface definition
interface Resizable {
    void resize(int width, int height);
}

// Implement multiple interfaces
// DocumentClass definition
class Document implements Printable, Resizable {
    String content;

    Document(String content) {
        this.content = content;
    }
    @Override
    // printMethod definition
    public void print() {
        System.out.println("Print: " + content);
    }
    @Override
    // resizeMethod definition
    public void resize(int width, int height) {
        System.out.println("Resize: " + width + "x" + height);
    }
}

// MainClass definition
public class Main {
    public static void main(String[] args) {
        Document doc = new Document("Report");
        doc.print();                // Print: Report
        doc.resize(800, 600);       // Resize: 800x600

        Printable p = doc;          // Reference with interface type
        p.print();                  // Print: Report
    }
}

