// LoggerInterface definition
interface Logger {
    void write(String message);  // Abstract method

    // Default method
    default void log(String message) {
        System.out.println("[LOG] " + message);
        write(message);
    }

    // staticMethod
    // createTimestampMethod definition
    static String createTimestamp() {
        return java.time.LocalDateTime.now().toString();
    }
}

// ConsoleLoggerClass definition
class ConsoleLogger implements Logger {
    @Override
    // writeMethod definition
    public void write(String message) {
        System.out.println("Console: " + message);
    }
    // log() can be used without overriding
}

// MainClass definition
public class Main {
    public static void main(String[] args) {
        ConsoleLogger logger = new ConsoleLogger();
        logger.log("Test");
        // [LOG] Test
        // Console: Test

        // Variable declaration and initialization
        String ts = Logger.createTimestamp(); // staticInvocation
        System.out.println(ts);
    }
}

