// MeasurableInterface definition
interface Measurable {
    double getMeasure();
}

// ShapeClass definition
abstract class Shape implements Measurable {
    String name;

    Shape(String name) {
        this.name = name;
    }
    abstract double area();

    @Override
    // getMeasureMethod definition
    public double getMeasure() {
        return area();  // Returns area as a measurement value
    }
    @Override
    // toStringMethod definition
    public String toString() {
        return name + "(Area: " + area() + ")";
    }
}

// RectangleClass definition
class Rectangle extends Shape {
    double width, height;

    Rectangle(double w, double h) {
        super("Rectangle");
        this.width = w;
        this.height = h;
    }
    @Override
    double area() {
        return width * height;
    }
}

// MainClass definition
public class Main {
    public static void main(String[] args) {
        Shape s = new Rectangle(3, 4);
        System.out.println(s);               // Rectangle(Area: 12.0)
        System.out.println(s.getMeasure());   // 12.0
    }
}

